VALUES
  ('pukao-d0d1b9a2-moex-00284', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '管理階層在財務報表附註中說明由於特殊情況，某一項目若依所適用之財務報導架構處理反易誤 導財務報表使用者，故另做適當之處理及表達，且亦詳述其原由及作法，會計師亦認同管理階層 的看法，此時會計師如何出具查核報告？', '["無保留意見，並於其他事項段增加相關說明", "無保留意見，並於強調事項段增加相關說明", "保留意見，並於強調事項段增加相關說明", "保留意見，並於其他事項段增加相關說明"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": "52ff4912de83", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00285', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '依審計準則公報第47號「財務報表查核之規劃」之規定，查核之規劃可分整體查核策略與查核計 畫，下列何者非訂定整體查核策略時應執行之程序？', '["辨認查核案件之特性以決定查核範圍", "確定查核案件之報導目的，以規劃查核之時間及須溝通之內容與方式", "確認執行查核案件所需資源之性質、時間及範圍", "對個別項目聲明所規劃進一步查核程序之性質、時間及範圍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": "52ff4912de83", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00286', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '在查核工作即將結束時，下列何者並非查核人員編製「未更正不實表達彙整表」之目的？', '["彙總不實表達，以便受查者作為改進會計處理及相關內控之依據", "讓受查者知道查核人員認真盡責", "判斷其對財務報表之影響是否重大，而影響查核意見", "作為要求管理階層更正不實表達之依據"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": "52ff4912de83", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00287', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '下列何者提供最可靠的查核證據？', '["從受查者處取得書面函證金額，得知應收帳款餘額", "從受查者之顧客處取得書面函證金額，得知應收帳款餘額", "從受查者處取得顧客寄發之對帳單，得知應收帳款餘額", "直接與受查者之顧客電話聯絡，得知應收帳款餘額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": "52ff4912de83", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00288', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '依據審計準則公報第44號「查核歷史性財務資訊之品質管制」之規定，有關查核案件之品質管制 敘述，下列何者正確？', '["查核案件之整體品質應由事務所風險管理部門負責", "品質覆核會計師應負責查核案件之指導、監督及執行，俾確信查核工作係依據專業準則及法令 執行，且所出具之查核報告於當時情況下係屬適當", "查核團隊成員間、查核團隊與被諮詢者間，或主辦會計師與案件品質管制複核人員間存有歧見 時，應以主辦會計師意見為主，因其負責出具查核報告", "主辦會計師應確認查核團隊具備適當之專業能力與足夠之時間及人力，且能依據專業準則及法 令執行查核工作，並於當時情況下出具適當之查核報告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": "52ff4912de83", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00289', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '依據審計準則公報第68號「內部控制缺失之溝通」規定，有關內部控制缺失之敘述，下列何者錯 誤？', '["內部控制顯著缺失應以書面及時與治理單位溝通", "內部控制缺失如發生在易造成損失或舞弊之資產，可能為顯著缺失", "數個內部控制缺失可能構成顯著缺失", "查核人員於前期發現且曾與管理階層溝通之內部控制其他缺失，管理階層因成本考量未予改 正，則查核人員於當期仍應提出再要求管理階層改正"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": "52ff4912de83", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00290', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '有關查核風險與重大性之敘述，下列何者錯誤？', '["查核人員應辨認及評估重大不實表達風險，以利考量重大性及查核風險", "固有風險與偵查風險存有反向關係", "控制風險與重大不實表達風險存有反向關係", "受查者之重大不實表達風險越高，查核人員所需取得之查核證據越多"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": "52ff4912de83", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00291', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '有關受查者出具的書面聲明，下列敘述何者正確？', '["書面聲明得取代必要之查核程序", "書面聲明自身無法對所涉及之事項提供足夠且適切之查核證據", "書面聲明之日期應與查核報告交付日相同", "合併財務報表僅係集團企業基於實質重於形式之目的而編製，故會計師受任對合併財務報表表 示意見時，不必取得書面聲明"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": "52ff4912de83", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00292', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '管理階層聲明財務狀況表上的存貨是真實的（bonafide），與下列何種個別項目聲明最相關？', '["存在", "完整", "評價", "截止"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": "52ff4912de83", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00293', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '繼任會計師取得委任人同意後與前任會計師連繫，前任會計師對部分查詢事項表示委任人限制其 答覆，故無法就其所知悉之事實詳細答覆，該繼任會計師應如何因應？', '["拒絕受任", "向委任人詢問理由，以決定是否接受委任", "若委任人同意接受可能簽發無法表示意見的前提，則可接受委任", "對未被詳細答覆的查詢事項另行蒐集充分及適切證據，以決定是否接受委任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "4b703e304d32", "answer_pdf_sha1": "52ff4912de83", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL)
